#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int odd = 0, x;
        for (int i = 0; i < N; ++i) {
            scanf("%d", &x);
            if (x & 1) ++odd;
        }
        if (odd >= 2 && (odd % 2 == 0))
            printf("YES\n");
        else
            printf("NO\n");
    }
    return 0;
}

