import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        odd = 0
        for _ in range(N):
            if int(next(it)) & 1:
                odd += 1
        out.append('YES' if odd >= 2 and odd % 2 == 0 else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

